export function getPrologue(id: number|string): string {
  return SCENARIO_DIALOGUES[String(id)]?.prologue || '';
}
export function getScenarioTitle(id: number|string): string {
  return SCENARIO_DIALOGUES[String(id)]?.title || `Scenario ${id}`;
}
export function getDialogueLines(id: number|string): DialogueLine[] {
  const sc = SCENARIO_DIALOGUES[String(id)];
  if (!sc) return [];
  const r: DialogueLine[] = [];
  for (const seq of sc.dialogues) for (const l of seq.lines) r.push(l);
  return r;
}